(213, 'Bùa Trí Tuệ', 13, 3, 'Tiềm năng và sức mạnh của bạn sẽ nhận được gấp đôi trong 1 khoảng thời gian, kể từ lúc mua', 0, 0, -1, 1403, -1, 0, -1, -1, -1, '[]', -1, 0),
(214, 'Bùa Mạnh Mẽ', 13, 3, 'Cú đấm của bạn sẽ mạnh hơn. Tăng 150% sức đánh hiện có khi bạn đánh Quái trong 1 khoảng thời gian, kể từ lúc mua', 0, 0, -1, 1404, -1, 0, -1, -1, -1, '[]', -1, 0),
(215, 'Bùa Da Trâu', 13, 3, 'Tăng sức chịu đòn cho bạn. Khi bị quái đánh, máu sẽ mất ít hơn, chỉ còn 50% bình thường. Có tác dụng trong 1 khoảng thời gian kể từ lúc mua', 0, 0, -1, 1405, -1, 0, -1, -1, -1, '[]', -1, 0),
(216, 'Bùa Oai Hùng', 13, 3, 'Bạn sẽ oai vệ hơn. Quái Thủ Lĩnh sẽ sợ bạn và đánh bạn yếu đi, y như con quái thường. Có tác dụng trong 1 khoảng thời gian kể từ lúc mua', 0, 0, -1, 1406, -1, 0, -1, -1, -1, '[]', -1, 0),
(217, 'Bùa Bất Tử', 13, 3, 'Bạn sẽ không bao giờ bị quái đánh chết. Thay vào đó chỉ còn 1 máu. Tuy nhiên bạn phải bơm máu mới có thể đánh lại. Có tác dụng trong 1 khoảng thời gian kể từ lúc mua.', 0, 0, -1, 1407, -1, 0, -1, -1, -1, '[]', -1, 0),
(218, 'Bùa Dẻo Dai', 13, 3, 'Thể lực của bạn sẽ không bao giờ giảm khi bùa này có tác dụng. Có tác dụng trong 1 khoảng thời gian, kể từ lúc mua', 0, 0, -1, 1408, -1, 0, -1, -1, -1, '[]', -1, 0),
(219, 'Bùa Thu Hút', 13, 3, 'Vật phẩm bạn đánh văng ra nếu là của bạn, nó sẽ tự bay vào người. Bạn sẽ không phải nhặt bằng tay. Có tác dụng trong 1 khoảng thời gian, kể từ lúc mua', 0, 0, -1, 1409, -1, 0, -1, -1, -1, '[]', -1, 0),
