INSERT INTO `nr_task` (`id`, `name`, `details`, `subnames`, `counts`, `npcs`, `maps`, `contents`, `reward_power`, `reward_potential`, `reward_gold`, `reward_gem`, `reward_gem_lock`) VALUES
(0, 'Nhiệm vụ đầu tiên (0)', '[\"Chi tiết nhiệm vụ\",\"Chi tiết nhiệm vụ\",\"Chi tiết nhiệm vụ\"]', '[[\"Hãy di chuyển nhân vật\",\"Đi đến nhà Gôhan\",\"Nói chuyện với ông Gôhan\",\"Mở rương đồ\",\"Thu hoạch đậu thần\",\"Báo cáo với Gôhan\",\"\"],[\"Hãy di chuyển nhân vật\",\"Đi đến nhà Moori\",\"Nói chuyện với ông Moori\",\"Mở rương đồ\",\"Thu hoạch đậu thần\",\"Báo cáo với ông Moori\",\"\"],[\"Hãy di chuyển nhân vật\",\"Đi đến nhà Broly\",\"Nói chuyện với ông Paragus\",\"Mở rương đồ\",\"Thu hoạch đậu thần\",\"Báo cáo với ông Paragus\",\"\"]]', '[-1,-1,-1,-1,-1,-1,-1]', '[[-1,-1,0,3,4,0,-1],[-1,-1,2,3,4,2,-1],[-1,-1,1,3,4,1,-1]]', '[[-1,21,-1,-1,-1,-1,-1],[-1,22,-1,-1,-1,-1,-1],[-1,23,-1,-1,-1,-1,-1]]', '[[\"\",\"\",\"\",\"#Rương đồ đằng kia,  đi đến gần và click đôi vào rương để mở\\nChọn lấy Rađa để sử dụng\",\"Bạn có thể thu hoạch đậu thần ở cây đậu đằng kia\",\"Nào, bây giờ bạn có thể gặp ông Gôhan để báo cáo rồi!\",\"\"],[\"\",\"\",\"\",\"#Rương đồ đằng kia,  đi đến gần và click đôi vào rương để mở\\nChọn lấy Rađa để sử dụng\",\"Bạn có thể thu hoạch đậu thần ở cây đậu đằng kia\",\"Nào, bây giờ bạn có thể gặp ông Moori để báo cáo rồi!\",\"\"],[\"\",\"\",\"\",\"#Rương đồ đằng kia,  đi đến gần và click đôi vào rương để mở\\nChọn lấy Rađa để sử dụng\",\"Bạn có thể thu hoạch đậu thần ở cây đậu đằng kia\",\"Nào, bây giờ bạn có thể gặp ông Paragus để báo cáo rồi!\",\"\"]]', 0, 0, 0, 0, 0),
(1, 'Nhiệm vụ tập luyện (1)', '[\"Mộc nhân được đặt nhiều tại Làng Aru, ngay trước nhà ông Gôhan\r\nHãy đánh ngã 5 mộc nhân, sau đó quay về nhà báo cáo với ông Gôhan\r\nĐể đánh, hãy click đôi vào đối tượng\",\"Mộc nhân được đặt nhiều tại Làng Mori, ngay trước nhà ông Moori\r\nHãy đánh ngã 5 mộc nhân, sau đó quay về nhà báo cáo với ông Moori\r\nĐể đánh, hãy click đôi vào đối tượng\",\"Mộc nhân được đặt nhiều tại Làng Kakarot, ngay trước nhà ông Paragus\r\nHãy đánh ngã 5 mộc nhân, sau đó quay về nhà báo cáo với ông Paragus\r\nĐể đánh, hãy click đôi vào đối tượng\"]', '[[\"Đánh ngã 5 mộc nhân\",\"Báo cáo với ông Gôhan\"],[\"Đánh ngã 5 mộc nhân\",\"Báo cáo với ông Moori\"],[\"Đánh ngã 5 mộc nhân\",\"Báo cáo với ông Paragus\"]]', '[5,-1]', '[[-1,0],[-1,2],[-1,1]]', '[[0,21],[7,22],[14,23]]', '[[\"\",\"Chúc mừng bạn đã hoàn thành nhiệm vụ. Nào, bây giờ bạn có thể gặp ông Gôhan để báo cáo rồi!\"],[\"\",\"Chúc mừng bạn đã hoàn thành nhiệm vụ. Nào, bây giờ bạn có thể gặp ông Moori để báo cáo rồi!\"],[\"\",\"Chúc mừng bạn đã hoàn thành nhiệm vụ. Nào, bây giờ bạn có thể gặp ông Paragus để báo cáo rồi!\"]]', 500, 500, 0, 0, 0),
(2, 'Nhiệm vụ thử thách (2)', '[\"Khủng long xuất hiện tại Đồi hoa cúc.\r\nHãy đánh bại khủng long, thu thập đủ 10 đùi gà sau đó quay về nhà báo cáo với ông Gôhan.\r\nĐể đánh, hãy click đôi vào đối tượng.\",\"Lợn lòi xuất hiện tại Đồi nấm tím.\r\nHãy đánh bại lợn lòi, thu thập đủ 10 đùi gà sau đó quay về nhà báo cáo với ông Moori.\r\nĐể đánh, hãy click đôi vào đối tượng.\",\"Quỷ đất xuất hiện tại Đồi hoang.\r\nHãy đánh bại quỷ đất, thu thập đủ 10 đùi gà sau đó quay về nhà báo cáo với ông Paragus.\r\nĐể đánh, hãy click đôi vào đối tượng.\"]', '[[\"Thu thập 10 đùi gà\",\"Báo cáo với ông Gôhan\"],[\"Thu thập 10 đùi gà\",\"Báo cáo với ông Moori\"],[\"Thu thập 10 đùi gà\",\"Báo cáo với ông Paragus\"]]', '[10,-1]', '[[-1,0],[-1,2],[-1,1]]', '[[1,21],[18,22],[15,23]]', '[[\"#Để sử dụng bản đồ, hãy mở menu, mục Nhiệm vụ, chọn Bản Đồ\\nVị trí đang chớp sáng là nơi bạn làm nhiệm vụ, hãy tìm đường đến đó\",\"Chúc mừng bạn đã hoàn thành nhiệm vụ. Nào, bây giờ bạn có thể gặp ông Gôhan để báo cáo rồi!\"],[\"#Để sử dụng bản đồ, hãy mở menu, mục Nhiệm vụ, chọn Bản Đồ\\nVị trí đang chớp sáng là nơi bạn làm nhiệm vụ, hãy tìm đường đến đó\",\"Chúc mừng bạn đã hoàn thành nhiệm vụ. Nào, bây giờ bạn có thể gặp ông Moori để báo cáo rồi!\"],[\"#Để sử dụng bản đồ, hãy mở menu, mục Nhiệm vụ, chọn Bản Đồ\\nVị trí đang chớp sáng là nơi bạn làm nhiệm vụ, hãy tìm đường đến đó\",\"Chúc mừng bạn đã hoàn thành nhiệm vụ. Nào, bây giờ bạn có thể gặp ông Paragus để báo cáo rồi!\"]]', 1000, 1000, 0, 0, 0),
(3, 'Nhiệm vụ sao băng (3)', '[\"Dùng tiềm năng con có để nâng cấp HP, KI hoặc Sức đánh\r\nKiểm tra khu vực sao băng rơi tại Vách núi Aru\",\"Dùng tiềm năng con có để nâng cấp HP, KI hoặc Sức đánh\r\nKiểm tra khu vực sao băng rơi tại Vách núi Mori\",\"Dùng tiềm năng con có để nâng cấp HP, KI hoặc Sức đánh\r\nKiểm tra khu vực sao băng rơi tại Vách núi Kakarot\"]', '[[\"Dùng tiềm năng\",\"Tìm kiếm sao băng\",\"Báo cáo với ông Gôhan\"],[\"Dùng tiềm năng\",\"Tìm kiếm sao băng\",\"Báo cáo với ông Moori\"],[\"Dùng tiềm năng\",\"Tìm kiếm sao băng\",\"Báo cáo với ông Paragus\"]]', '[-1,-1,-1]', '[[-1,-1,0],[-1,-1,2],[-1,-1,1]]', '[[-1,42,21],[-1,43,22],[-1,44,23]]', '[[\"#Chúc mừng bạn vừa nhận được 1.000 tiềm năng\\nMở menu chọn mục kỹ năng, dùng điểm tiềm năng cộng vào HP, KI hoặc Sức đánh\",\"\",\"Hãy bế cậu bé về nhà!\"],[\"#Chúc mừng bạn vừa nhận được 1.000 tiềm năng\\nMở menu chọn mục kỹ năng, dùng điểm tiềm năng cộng vào HP, KI hoặc Sức đánh\",\"\",\"Hãy bế cậu bé về nhà!\"],[\"#Chúc mừng bạn vừa nhận được 1.000 tiềm năng\\nMở menu chọn mục kỹ năng, dùng điểm tiềm năng cộng vào HP, KI hoặc Sức đánh\",\"\",\"Hãy bế cậu bé về nhà!\"]]', 2000, 2000, 0, 0, 0),
(6, 'Nhiệm vụ (6)', '[\"Khủng long mẹ sống tại Trái Đất\r\nLợn lòi mẹ sống tại Namếc\r\nQuỷ đất mẹ sống tại Xayda\r\nDùng tàu vũ trụ để di chuyển sang hành tinh khác\",\"Khủng long mẹ sống tại Trái Đất\r\nLợn lòi mẹ sống tại Namếc\r\nQuỷ đất mẹ sống tại Xayda\r\nDùng tàu vũ trụ để di chuyển sang hành tinh khác\",\"Khủng long mẹ sống tại Trái Đất\r\nLợn lòi mẹ sống tại Namếc\r\nQuỷ đất mẹ sống tại Xayda\r\nDùng tàu vũ trụ để di chuyển sang hành tinh khác\"]', '[[\"Đánh 3 con khủng long mẹ\",\"Đánh 3 con lợn lòi mẹ\",\"Đánh 3 con quỷ đất mẹ\",\"Báo cáo với ông Gôhan\"],[\"Đánh 3 con lợn lòi mẹ\",\"Đánh 3 con quỷ đất mẹ\",\"Đánh 3 con khủng long mẹ\",\"Báo cáo với ông Moori\"],[\"Đánh 3 con quỷ đất mẹ\",\"Đánh 3 con khủng long mẹ\",\"Đánh 3 con lợn lòi mẹ\",\"Báo cáo với ông Paragus\"]]', '[3,3,3,-1]', '[[-1,-1,-1,0],[-1,-1,-1,2],[-1,-1,-1,1]]', '[[16,2,9,21],[16,2,9,22],[16,2,9,23]]', '[[\"Bạn vừa nhận được bản đồ của hành tinh tiếp theo\",\"#Tốt lắm, bây giờ hãy đến hành tinh tiếp theo nào\\nĐể di chuyển đến hành tinh khác, bạn hãy đến Trạm Phi Thuyền, gặp Cui\\nNhanh lên, mọi người đang cần sự giúp đỡ của bạn đấy\",\"Mau đến hành tinh tiếp theo nào. Nhanh lên, mọi người đang cần sự giúp đỡ của bạn đấy\",\"Xong việc rồi, về báo cáo với ông Gôhan nào!\"],[\"Bạn vừa nhận được bản đồ của hành tinh tiếp theo\",\"#Tốt lắm, bây giờ hãy đến hành tinh tiếp theo nào\\nĐể di chuyển đến hành tinh khác, bạn hãy đến Trạm Phi Thuyền, gặp Cui\\nNhanh lên, mọi người đang cần sự giúp đỡ của bạn đấy\",\"Mau đến hành tinh tiếp theo nào. Nhanh lên, mọi người đang cần sự giúp đỡ của bạn đấy\",\"Xong việc rồi, về báo cáo với ông Moori nào!\"],[\"Bạn vừa nhận được bản đồ của hành tinh tiếp theo\",\"#Tốt lắm, bây giờ hãy đến hành tinh tiếp theo nào\\nĐể di chuyển đến hành tinh khác, bạn hãy đến Trạm Phi Thuyền, gặp Cui\\nNhanh lên, mọi người đang cần sự giúp đỡ của bạn đấy\",\"Mau đến hành tinh tiếp theo nào. Nhanh lên, mọi người đang cần sự giúp đỡ của bạn đấy\",\"Xong việc rồi, về báo cáo với ông Paragus nào!\"]]', 4000, 4000, 0, 0, 0),
(7, 'Nhiệm vụ giải cứu (7)', '[\"Tìm đường đến Rừng nấm, hạ 5 con quỷ bay\",\"Tìm đến Thung lũng Maima, hạ 5 con phi long\",\"Tìm đường đến Rừng nguyên sinh, hạ  con quỷ bay\"]', '[[\"Đạt 16.000 sức mạnh\",\"Đánh bại 5 con thằn lằn bay\",\"Nói chuyện với Bunma\",\"Báo cáo với ông Gôhan\"],[\"Đạt 16.000 sức mạnh\",\"Đánh bại 5 con phi long\",\"Nói chuyện với Dende\",\"Báo cáo với ông Moori\"],[\"Đạt 16.000 sức mạnh\",\"Đánh bại 5 con quỷ bay\",\"Nói chuyện với Appule\",\"Báo cáo với ông Paragus\"]]', '[1,5,-1,-1]', '[[-1,-1,7,0],[-1,-1,8,2],[-1,-1,9,1]]', '[[-1,3,0,21],[-1,12,7,22],[-1,17,14,23]]', '[[\"\",\"Bạn đã đạt sức mạnh yêu cầu, đi làm nhiệm vụ nào\",\"Bạn vừa cứu được Bunma hãy về Làng Aru và nói chuyện với Gôhan\",\"Xong việc rồi, về báo cáo với ông Gôhan nào!\"],[\"\",\"Bạn đã đạt sức mạnh yêu cầu, đi làm nhiệm vụ nào\",\"Bạn vừa cứu được Dende hãy về Làng Moori và nói chuyện với Dende\",\"Xong việc rồi, về báo cáo với ông Moori nào!\"],[\"\",\"Bạn đã đạt sức mạnh yêu cầu, đi làm nhiệm vụ nào\",\"Bạn vừa cứu được Appule hãy về Làng Kakarot và nói chuyện với Appule\",\"Xong việc rồi, về báo cáo với ông Paragus nào!\"]]', 8000, 8000, 0, 0, 0),
(8, 'Nhiệm vụ tìm ngọc (8)', '[\"Ngọc rồng 7 sao đang bị bọn phi long mẹ cướp đi tại Vực maima, Namếc. Đánh bại chúng để tìm lại.\",\"Ngọc rồng 7 sao đang bị bọn quỷ bay mẹ cướp đi tại Rừng thông Xayda, Xayda. Đánh bại chúng để tìm lại.\",\"Ngọc rồng 7 sao đang bị bọn thằn lằn mẹ cướp đi tại Rừng xương, Trái Đất. Đánh bại chúng để tìm lại.\"]', '[[\"Đạt 40.000 sức mạnh\",\"Tìm viên ngọc rồng 7 sao\",\"Đem ngọc về cho ông Gôhan\",\"Tìm tháp Karin\"],[\"Đạt 40.000 sức mạnh\",\"Tìm viên ngọc rồng 7 sao\",\"Đem ngọc về cho ông Moori\",\"Tìm tháp Karin\"],[\"Đạt 40.000 sức mạnh\",\"Tìm viên ngọc rồng 7 sao\",\"Đem ngọc về cho ông Paragus\",\"Tìm tháp Karin\"]]', '[-1,-1,-1,-1]', '[[-1,-1,0,17],[-1,-1,2,17],[-1,-1,1,17]]', '[[-1,12,21,47],[-1,18,22,47],[-1,4,23,47]]', '[[\"\",\"Bạn đã đạt sức mạnh yêu cầu, đi làm nhiệm vụ nào\",\"Tìm thấy viên ngọc rồng 7 sao rồi, đem về cho ông Gôhan nào!\",\"\"],[\"\",\"Bạn đã đạt sức mạnh yêu cầu, đi làm nhiệm vụ nào\",\"Tìm thấy viên ngọc rồng 7 sao rồi, đem về cho ông Moori nào!\",\"\"],[\"\",\"Bạn đã đạt sức mạnh yêu cầu, đi làm nhiệm vụ nào\",\"Tìm thấy viên ngọc rồng 7 sao rồi, đem về cho ông Paragus nào!\",\"\"]]', 15000, 15000, 0, 0, 0),
(9, 'Nhiệm vụ tìm ngọc (9)', '[\"Tìm đường đến Karin\nnói chuyện với Bò Mộng\nkhi đụng độ Tàu Pảy Pảy hãy mau chóng bay lên tháp Karin\",\"Tìm đường đến Karin\nnói chuyện với Bò Mộng\nkhi đụng độ Tàu Pảy Pảy hãy mau chóng bay lên tháp Karin\",\"Tìm đường đến Karin\nnói chuyện với Bò Mộng\nkhi đụng độ Tàu Pảy Pảy hãy mau chóng bay lên tháp Karin\"]', '[[\"Nói chuyện với Bò Mộng\",\"Đụng độ Tàu Pảy Pảy\",\"Bỏ chạy lên tháp Karin\",\"Nói chuyện với Thần Mèo\"],[\"Nói chuyện với Bò Mộng\",\"Đụng độ Tàu Pảy Pảy\",\"Bỏ chạy lên tháp Karin\",\"Nói chuyện với Thần Mèo\"],[\"Nói chuyện với Bò Mộng\",\"Đụng độ Tàu Pảy Pảy\",\"Bỏ chạy lên tháp Karin\",\"Nói chuyện với Thần Mèo\"]]', '[-1,-1,-1,-1]', '[[17,17,-1,18],[17,17,-1,18],[17,17,-1,18]]', '[[47,47,46,46],[47,47,46,46],[47,46,46,46]]', '[[\"Tìm và nói chiện với Bò Mộng\",\"Hình như có người đang tới đây\",\"Đây có phải là tên Tàu Pảy Pảy mà Bò Mộng nhắc đến ?, hãy thử sức xem nào\",\"Hãy đến nói chuyện với Thần Mèo Karin\"],[\"Tìm và nói chiện với Bò Mộng\",\"Hình như có người đang tới đây\",\"Đây có phải là tên Tàu Pảy Pảy mà Bò Mộng nhắc đến ?, hãy thử sức xem nào\",\"Hãy đến nói chuyện với Thần Mèo Karin\"],[\"Tìm và nói chiện với Bò Mộng\",\"Hình như có người đang tới đây\",\"Đây có phải là tên Tàu Pảy Pảy mà Bò Mộng nhắc đến ?, hãy thử sức xem nào\",\"Hãy đến nói chuyện với Thần Mèo Karin\"]]', 0, 0, 0, 0, 0),
(10, 'Nhiệm vụ tìm ngọc (10)', '[\"Học võ với Thần Mèo\r\nXuống rừng Karin tiêu diệt Tàu Pảy Pảy\r\nđem ngọc về cho ông Gôhan\",\"Học võ với Thần Mèo\r\nXuống rừng Karin tiêu diệt Tàu Pảy Pảy\r\nđem ngọc về cho ông Moori\",\"Học võ với Thần Mèo\r\nXuống rừng Karin tiêu diệt Tàu Pảy Pảy\r\nđem ngọc về cho ông Paragus\"]', '[[\"Đánh thắng Thần Mèo\",\"Tiêu diệt Tàu Pảy Pảy\",\"Nói chuyện với Bò Mộng\",\"Báo cáo với ông Gôhan\"],[\"Đánh thắng Thần Mèo\",\"Tiêu diệt Tàu Pảy Pảy\",\"Nói chuyện với Bò Mộng\",\"Báo cáo với ông Moori\"],[\"Đánh thắng Thần Mèo\",\"Tiêu diệt Tàu Pảy Pảy\",\"Nói chuyện với Bò Mộng\",\"Báo cáo với ông Paragus\"]]', '[-1,-1,-1,-1]', '[[18,-1,17,0],[18,-1,17,2],[18,-1,17,1]]', '[[46,47,47,21],[46,47,47,22],[46,47,47,23]]', '[[\"#Để luyện tập, hãy đến gặp thần mèo Karin, chọn mục Luyện tập\\nBạn cũng có thể luyện tập khi đang offline bằng cách thoát game sau khi chọn mục Luyện tập\\nKhi đủ khả năng ,hãy chọn mục thách đấu, nếu chiến thắng bạn có thể luyện tập với các đối thủ khác mạnh hơn\\nNgoài ra bạn cũng có thể tặng ngọc để chiến thắng\\nLuyện tập sẽ giúp tăng tiềm năng và sức mạnh, đối thủ càng mạnh sẽ tăng càng nhanh\",\"Đã đến lúc tiêu diệt Tàu Pảy Pảy\",\"Tàu Pảy Pảy đã bị tiêu diệt, hãy đến nói chuyện với Bò Mộng\",\"Viên ngọc rồng 6 sao đây rồi, đem về cho ông Gôhan nào!\"],[\"#Để luyện tập, hãy đến gặp thần mèo Karin, chọn mục Luyện tập\\nBạn cũng có thể luyện tập khi đang offline bằng cách thoát game sau khi chọn mục Luyện tập\\nKhi đủ khả năng ,hãy chọn mục thách đấu, nếu chiến thắng bạn có thể luyện tập với các đối thủ khác mạnh hơn\\nNgoài ra bạn cũng có thể tặng ngọc để chiến thắng\\nLuyện tập sẽ giúp tăng tiềm năng và sức mạnh, đối thủ càng mạnh sẽ tăng càng nhanh\",\"Đã đến lúc tiêu diệt Tàu Pảy Pảy\",\"Tàu Pảy Pảy đã bị tiêu diệt, hãy đến nói chuyện với Bò Mộng\",\"Viên ngọc rồng 6 sao đây rồi, đem về cho ông Moori nào!\"],[\"#Để luyện tập, hãy đến gặp thần mèo Karin, chọn mục Luyện tập\\nBạn cũng có thể luyện tập khi đang offline bằng cách thoát game sau khi chọn mục Luyện tập\\nKhi đủ khả năng ,hãy chọn mục thách đấu, nếu chiến thắng bạn có thể luyện tập với các đối thủ khác mạnh hơn\\nNgoài ra bạn cũng có thể tặng ngọc để chiến thắng\\nLuyện tập sẽ giúp tăng tiềm năng và sức mạnh, đối thủ càng mạnh sẽ tăng càng nhanh\",\"Đã đến lúc tiêu diệt Tàu Pảy Pảy\",\"Tàu Pảy Pảy đã bị tiêu diệt, hãy đến nói chuyện với Bò Mộng\",\"Viên ngọc rồng 6 sao đây rồi, đem về cho ông Paragus nào!\"]]', 15000, 15000, 0, 0, 0),
(11, 'Nhiệm vụ bái sư (11)', '[\"Tìm Quy lão Kame tại Đảo Kame bái sư học võ\",\"Tìm Trưởng lão Guru tại Đảo Guru bái sư học võ\",\"Tìm Vua Vegeta tại Vách núi đen bái sư học võ\"]', '[[\"Tìm Quy lão Kame tại Đảo Kame\",\"Tặng ngài cuốn truyện Đôrêmon\"],[\"Tìm Trưởng lão Guru tại Đảo Guru\",\"Tặng ngài cuốn truyện Đôrêmon\"],[\"Tìm Vua Vegeta tại Vách núi đen\",\"Tặng ngài cuốn truyện Đôrêmon\"]]', '[-1,-1]', '[[13,13],[14,14],[15,15]]', '[[5,5],[13,13],[20,20]]', '[[\"\",\"\"],[\"\",\"\"],[\"\",\"\"]]', 5000, 5000, 0, 0, 0),
(12, 'Nhiệm vụ gia nhập bang hội (12)', '[\"Báo cáo với Quy lão Kame khi bang của bạn có từ 5 thành viên trở lên\",\"Báo cáo với Trưởng lão Guru  khi bang của bạn có từ 5 thành viên trở lên\",\"Báo cáo với Vua Vegeta khi bang của bạn có từ 5 thành viên trở lên\"]', '[[\"Vào 1 bang hội\",\"Báo cáo với Quy lão Kame\"],[\"Vào 1 bang hội\",\"Báo cáo với Trưởng lão Guru\"],[\"Vào 1 bang hội\",\"Báo cáo với Vua Vegeta\"]]', '[-1,-1]', '[[-1,13],[-1,14],[-1,15]]', '[[-1,5],[-1,13],[-1,20]]', '[[\"\",\"\"],[\"\",\"\"],[\"\",\"\"]]', 20000, 20000, 0, 0, 0),
(13, 'Nhiệm vụ bang hội đầu tiên (13)', '[\"\r\nHeo rừng tại Rừng dương xỉ (Trái đất)\r\nHeo da xanh tại Núi hoa tím (Namếc)\r\nHeo Xayda tại Rừng đá (Xayda)\r\nBáo cáo với Quy lão Kame\",\"Cùng ít nhất 2 thành viên trong bang tiêu diệt\r\nHeo rừng tại Rừng dương xỉ (Trái đất)\r\nHeo da xanh tại Núi hoa tím (Namếc)\r\nHeo Xayda tại Rừng đá (Xayda)\r\nBáo cáo với Quy lão Kame\",\"Cùng ít nhất 2 thành viên trong bang tiêu diệt\r\nHeo rừng tại Rừng dương xỉ (Trái đất)\r\nHeo da xanh tại Núi hoa tím (Namếc)\r\nHeo Xayda tại Rừng đá (Xayda)\r\nBáo cáo với quy lão Kame\"]', '[[\"Tiêu diệt Heo rừng\",\"Tiêu diệt Heo da xanh\",\"Tiêu diệt Heo Xayda\",\"Báo cáo với Quy lão Kame\"],[\"Tiêu diệt Heo rừng\",\"Tiêu diệt Heo da xanh\",\"Tiêu diệt Heo Xayda\",\"Báo cáo với Trưởng lão Guru\"],[\"Tiêu diệt Heo rừng\",\"Tiêu diệt Heo da xanh\",\"Tiêu diệt Heo Xayda\",\"Báo cáo với Vua Vegeta\"]]', '[10,10,10,-1]', '[[-1,-1,-1,13],[-1,-1,-1,13],[-1,-1,-1,13]]', '[[28,32,36,5],[28,32,36,5],[28,32,36,5]]', '[[\"Heo rừng tại Rừng dương xỉ\",\"Heo da xanh tại Núi hoa tím\",\"Heo Xayda tại Rừng đá\",\"Nhiệm vụ hoàn thành, báo cáo với Quy lão Kame nào!\"],[\"Heo rừng tại Rừng dương xỉ\",\"Heo da xanh tại Núi hoa tím\",\"Heo Xayda tại Rừng đá\",\"Nhiệm vụ hoàn thành, báo cáo với Trưởng lão Guru nào!\"],[\"Heo rừng tại Rừng dương xỉ\",\"Heo da xanh tại Núi hoa tím\",\"Heo Xayda tại Rừng đá\",\"Nhiệm vụ hoàn thành, báo cáo với Vua Vegeta nào!\"]]', 50000, 50000, 0, 0, 0),
