(27, 'Truy tìm Mabư (27)', '[\"Đến đại hội võ thuật gặp Osin sau đó đi theo hướng dẫn của Osin để truy tìm Mabu cũng như các đồng đảng của chúng\",\"Đến đại hội võ thuật gặp Osin sau đó đi theo hướng dẫn của Osin để truy tìm Mabu cũng như các đồng đảng của chúng.\",\"Đến đại hội võ thuật gặp Osin sau đó đi theo hướng dẫn của Osin để truy tìm Mabu cũng như các đồng đảng của chúng.\"]', '[[\"Đến Đại Hội Võ thuật gặp Osin\",\"Tiêu diệt 20 Drabura\",\"Tiêu diệt 20 BuiBui\",\"Tiệu diệt 20 Yacon\",\"Tiêu diệt 20 Mabu\",\"Quay trở lại trả nhiệm vụ cho Osin\"]\r\n,[\"Đến Đại Hội Võ thuật gặp Osin\",\"Tiêu diệt 20 Drabura\",\"Tiêu diệt 20 BuiBui\",\"Tiệu diệt 20 Yacon\",\"Tiêu diệt 20 Mabu\",\"Quay trở lại trả nhiệm vụ cho Osin\"]\r\n,[\"Đến Đại Hội Võ thuật gặp Osin\",\"Tiêu diệt 20 Drabura\",\"Tiêu diệt 20 BuiBui\",\"Tiệu diệt 20 Yacon\",\"Tiêu diệt 20 Mabu\",\"Quay trở lại trả nhiệm vụ cho Osin\"]]', '[-1,20,20,20,20,-1]', '[[44,-1,-1,-1,-1,44],[44,-1,-1,-1,-1,44],[44,-1,-1,-1,-1,44]]', '[[52,-1,-1,-1,-1,52],[52,-1,-1,-1,-1,52],[52,-1,-1,-1,-1,52]]', '[[\"Đến Đại Hội Võ thuật gặp Osin\",\"Tiêu diệt 20 Drabura\",\"Tiêu diệt 20 BuiBui\",\"Tiệu diệt 20 Yacon\",\"Tiêu diệt 20 Mabu\",\"Quay trở lại trả nhiệm vụ cho Osin\"]\r\n,[\"Đến Đại Hội Võ thuật gặp Osin\",\"Tiêu diệt 20 Drabura\",\"Tiêu diệt 20 BuiBui\",\"Tiệu diệt 20 Yacon\",\"Tiêu diệt 20 Mabu\",\"Quay trở lại trả nhiệm vụ cho Osin\"]\r\n,[\"Đến Đại Hội Võ thuật gặp Osin\",\"Tiêu diệt 20 Drabura\",\"Tiêu diệt 20 BuiBui\",\"Tiệu diệt 20 Yacon\",\"Tiêu diệt 20 Mabu\",\"Quay trở lại trả nhiệm vụ cho Osin\"]]', 0, 0, 0, 0, 0),
